def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        base_adjust = np.log1p(abs(capacity - item))
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.5)
            if capacity > 10:
                priority += 200 * np.sqrt(capacity) + 70 * np.cos(capacity * np.pi / 4)
                if capacity > 20:
                    for z in range(3, 8):
                        priority += ((-1)**z) * np.sin(z * capacity) * 25 / z
                else:
                    priority -= 50 * usage_ratio
            else:
                priority -= 40 * usage_ratio
            for p in range(1, 6):
                priority += ((-1)**(p+1)) * np.cos(usage_ratio * np.pi * p * 1.5) * 18 / (p + 1)
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 2500 * delta**1.7 + 180 * (1 - delta**1.2)
            for q in range(1, 9):
                priority += np.sin(usage_ratio * np.pi * (q**1.3)) * 22 / q
            if capacity % 3 < 0.7:
                priority += 40 * np.tan(capacity / 15)
        elif 1.5 < usage_ratio <= 3:
            priority += 1200 * (usage_ratio - 1.5) ** 2
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.6:
                    priority += power * 18 / r
                    if r % 3 == 0:
                        priority += 4 * r
                else:
                    priority += (1 - power) * 14 / (r + 2)
                    if r == 9 and usage_ratio > 2:
                        priority += 15
            if capacity % 2.3 < 0.5:
                priority += 30 * np.sin(capacity * 3.1)
        elif 0.5 < usage_ratio <= 1.5:
            priority += 200 * (1.5 - usage_ratio) + 100 * (usage_ratio - 0.5)
            for x in range(1, 15):
                ratio_pow = usage_ratio ** (x/2)
                priority += (np.tanh(ratio_pow * np.pi / 2) - 0.3) * 12 / x
                if usage_ratio < 0.07 * x:
                    priority -= 10 * x
            if capacity < 0.15:
                priority += np.sqrt(capacity) * 280
            elif capacity < 1.0:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 5) * 18
        else:
            priority += 400 * (1 - usage_ratio)**3
            for y in range(1, 20):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 6) - 0.25) * 10 / y
                if usage_ratio < 0.015 * y:
                    priority -= 12 * y
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 25) * 45
            else:
                priority += (capacity % 6) * 28
        if capacity < 0.03:
            priority += 80
            if usage_ratio > 0.85:
                priority += 90
            elif usage_ratio < 0.12:
                priority -= 70
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 35
            for s in range(1, 7):
                if int(capacity * 1200) % (s + 4) == 0:
                    priority += s * 8
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 40
                for t in range(1, 8):
                    priority -= t * 5
            elif usage_ratio > 0.95:
                priority += 100
                for u in range(1, 5):
                    priority += u * 9
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 2500) % 19 == 0:
            proximity_score += 18
        if int(capacity * 900) % 23 == 0:
            proximity_score -= 12
        if int(capacity * 200) % 11 == 0:
            proximity_score += 15
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 10)
            if diff < 0.02:
                proximity_score += 25 / k
            elif diff < 0.05:
                proximity_score += 12 / k
            else:
                proximity_score -= 5 / k
        for m in range(1, 9):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1800) % (n + 6)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 7 * n
        priority += proximity_score
        if usage_ratio < 0.005:
            for s in range(1, 9):
                priority -= s * 12
        elif usage_ratio > 0.995:
            for t in range(1, 7):
                priority += t * 12
        if capacity > 2.0:
            if capacity % 1 < 0.05:
                priority += 50
            if (int(capacity * 2500) % 23 == 0) and (usage_ratio > 0.7):
                priority += 70
            for v in range(1, 7):
                if (int(capacity * 600) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 30
        priority += base_adjust * 5
        if np.isnan(priority) or np.isinf(priority):
            priority = 2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
